interface SettingsRowProps {
  icon: React.ElementType;
  label: string;
  description?: string;
  value?: string;
  onPress?: () => void;
  trailing?: React.ReactNode;
  variant?: "default" | "destructive";
}

function SettingsRow({
  icon: Icon,
  label,
  description,
  value,
  onPress,
  trailing,
  variant = "default",
}: SettingsRowProps) {
  const content = (
    <View className="flex-row items-center py-3">
      <View
        className={cn(
          "w-9 h-9 rounded-lg items-center justify-center mr-3",
          variant === "destructive" ? "bg-destructive/10" : "bg-muted"
        )}
      >
        <Icon
          size={18}
          color={variant === "destructive" ? "#ef4444" : "#a1a1aa"}
        />
      </View>
      <View className="flex-1">
        <Text
          className={cn(
            "text-sm font-medium",
            variant === "destructive" ? "text-destructive" : "text-foreground"
          )}
        >
          {label}
        </Text>
        {description && (
          <Text className="text-xs text-muted-foreground mt-0.5">
            {description}
          </Text>
        )}
      </View>
      {value && (
        <Text className="text-sm text-muted-foreground mr-2">{value}</Text>
      )}
      {trailing}
      {onPress && !trailing && (
        <ChevronRight size={16} color="#71717a" />
      )}
    </View>
  );

  if (onPress) {
    return (
      <Pressable onPress={onPress} className="active:bg-muted rounded-lg -mx-2 px-2">
        {content}
      </Pressable>
    );
  }

  return content;
}

