  --success: #10a37f;
  --warning: #f59e0b;
  --destructive: #ef4444;
  --brand: #10a37f;
  --brand-soft: #3fd7ad;
  --graphite: #0d120f;
}

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-border: var(--border);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-success: var(--success);
  --color-warning: var(--warning);
  --color-destructive: var(--destructive);
  --color-brand: var(--brand);
  --color-brand-soft: var(--brand-soft);
  --color-graphite: var(--graphite);
  --font-sans: var(--font-body-sans);
  --font-mono: var(--font-body-mono);
}

* {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  background: var(--background);
  color: var(--foreground);
  font-family: var(--font-body-sans), system-ui, sans-serif;
}

a {
  color: inherit;
  text-decoration: none;
}

::selection {
  background: rgba(16, 163, 127, 0.35);
  color: #f3f6f2;
}

/* Subtle grain texture overlay */
.grain::before {
  content: "";
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  opacity: 0.015;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
  z-index: 1000;
}

/* Smooth animations */
@keyframes fade-in {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes float-slow {
  0%, 100% { transform: translate3d(0, 0, 0) rotate(0deg); }
  50% { transform: translate3d(0, -10px, 0) rotate(0.5deg); }
}

@keyframes scan-line {
  0% { transform: translateY(-100%); opacity: 0; }
  15%, 80% { opacity: 1; }
  100% { transform: translateY(460%); opacity: 0; }
}

@keyframes fade-in-delay {
  0%, 50% { opacity: 0; transform: translateY(8px); }
  100% { opacity: 1; transform: translateY(0); }
}

.animate-fade-in {
  animation: fade-in 0.6s ease-out forwards;
}

.animate-fade-in-delay {
  animation: fade-in 0.6s ease-out 0.15s forwards;
  opacity: 0;
}

.animate-fade-in-delay-2 {
  animation: fade-in 0.6s ease-out 0.3s forwards;
  opacity: 0;
}

.animate-fade-in-delay-3 {
  animation: fade-in 0.6s ease-out 0.45s forwards;
  opacity: 0;
}

.animate-float-slow {
  animation: float-slow 8s ease-in-out infinite;
}

.animate-scan-line {
  animation: scan-line 4.5s ease-in-out infinite;
}

