import { memo } from "react";
import { View, Text } from "../../lib/tw";
import { cn } from "../../lib/utils";
import { type OffdexMessage } from "@offdex/protocol";

// ════════════════════════════════════════════════════════════════════════════
// Message Bubble Component
// ════════════════════════════════════════════════════════════════════════════

export interface MessageBubbleProps {
  message: OffdexMessage;
  isStreaming?: boolean;
}

export const MessageBubble = memo(function MessageBubble({
  message,
  isStreaming = false,
}: MessageBubbleProps) {
  const isUser = message.role === "user";
  const isAssistant = message.role === "assistant";

  return (
    <View
      className={cn(
        "px-4 py-2",
        isUser && "items-end"
      )}
    >
      {/* Role Label */}
      <Text className="text-xs font-medium text-muted-foreground mb-1.5 px-1">
        {isUser ? "You" : "Codex"}
      </Text>

      {/* Message Content */}
      <View
        className={cn(
          "rounded-lg px-4 py-3 max-w-[85%]",
          isUser && "bg-primary rounded-br-sm",
          isAssistant && "bg-card shadow-card rounded-bl-sm"
        )}
      >
        <Text
          className={cn(
            "text-sm leading-relaxed",
            isUser && "text-secondary-foreground",
            isAssistant && "text-foreground"
          )}
          selectable
        >
          {message.body}
        </Text>

        {/* Streaming indicator */}
        {isStreaming && isAssistant && (
          <View className="flex-row items-center gap-1 mt-2">
            <View className="h-1.5 w-1.5 rounded-full bg-muted-foreground animate-pulse" />
            <View className="h-1.5 w-1.5 rounded-full bg-muted-foreground animate-pulse" />
            <View className="h-1.5 w-1.5 rounded-full bg-muted-foreground animate-pulse" />
          </View>
        )}
      </View>

      {/* Timestamp */}
      <Text className="text-[10px] text-foreground-subtle mt-1 px-1">
        {message.createdAt}
      </Text>
    </View>
  );
});

// ════════════════════════════════════════════════════════════════════════════
// Working Indicator Component
// ════════════════════════════════════════════════════════════════════════════

export interface WorkingIndicatorProps {
  duration?: number;
}

export function WorkingIndicator({ duration }: WorkingIndicatorProps) {
  const formatDuration = (seconds: number) => {
    if (seconds < 60) return `${seconds}s`;
    const minutes = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${minutes}m ${secs}s`;
  };

  return (
    <View className="px-4 py-3">
        <View className="flex-row items-center gap-3 rounded-lg bg-card px-4 py-3 shadow-card">
        {/* Animated dots */}
        <View className="flex-row items-center gap-1">
          <View className="h-2 w-2 rounded-full bg-develop animate-pulse" />
          <View className="h-2 w-2 rounded-full bg-develop animate-pulse" />
          <View className="h-2 w-2 rounded-full bg-develop animate-pulse" />
        </View>

        <Text className="text-sm text-muted-foreground">
          Codex is working
          {duration !== undefined && (
            <Text className="text-foreground-subtle">
              {" "}· {formatDuration(duration)}
            </Text>
          )}
        </Text>
      </View>
    </View>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// System Message Component
// ════════════════════════════════════════════════════════════════════════════

export interface SystemMessageProps {
  message: string;
}

export function SystemMessage({ message }: SystemMessageProps) {
  return (
    <View className="px-4 py-2">
      <View className="rounded-lg bg-muted px-4 py-3 shadow-border">
        <Text className="text-xs text-muted-foreground text-center">
          {message}
        </Text>
      </View>
    </View>
  );
}
import { forwardRef } from "react";
import { Pressable, Text, ActivityIndicator, type PressableProps } from "../../lib/tw";
import { cn } from "../../lib/utils";
import * as Haptics from "expo-haptics";

// ════════════════════════════════════════════════════════════════════════════
// Button Variants
// ════════════════════════════════════════════════════════════════════════════

type ButtonVariant =
  | "default"
  | "primary"
  | "secondary"
  | "ghost"
  | "destructive"
  | "outline";
type ButtonSize = "default" | "sm" | "lg" | "icon";

const variantStyles: Record<ButtonVariant, string> = {
  default: "bg-primary",
  primary: "bg-primary",
  secondary: "bg-secondary shadow-border",
  ghost: "bg-transparent",
  destructive: "bg-destructive",
  outline: "bg-transparent shadow-border",
};

const variantTextStyles: Record<ButtonVariant, string> = {
  default: "text-primary-foreground",
  primary: "text-primary-foreground",
  secondary: "text-secondary-foreground",
  ghost: "text-foreground",
  destructive: "text-destructive-foreground",
  outline: "text-foreground",
};

const sizeStyles: Record<ButtonSize, string> = {
  default: "h-11 px-5 rounded-md",
  sm: "h-9 px-4 rounded-md",
  lg: "h-12 px-6 rounded-md",
  icon: "h-10 w-10 rounded-full",
};

const sizeTextStyles: Record<ButtonSize, string> = {
  default: "text-sm",
  sm: "text-xs",
  lg: "text-base",
  icon: "text-sm",
};

// ════════════════════════════════════════════════════════════════════════════
// Component
// ════════════════════════════════════════════════════════════════════════════

export interface ButtonProps extends Omit<PressableProps, "children"> {
  variant?: ButtonVariant;
  size?: ButtonSize;
  children?: React.ReactNode;
  loading?: boolean;
  disabled?: boolean;
  haptic?: boolean;
}

export const Button = forwardRef<React.ElementRef<typeof Pressable>, ButtonProps>(
  (
    {
      className,
      variant = "primary",
      size = "default",
      children,
      loading = false,
      disabled = false,
      haptic = true,
      onPress,
      ...props
    },
    ref
  ) => {
    const handlePress = (e: any) => {
      if (disabled || loading) return;
      if (haptic) {
        void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
      }
      onPress?.(e);
    };

    const isDisabled = disabled || loading;

    return (
      <Pressable
        ref={ref}
        className={cn(
          "flex-row items-center justify-center gap-2",
          "active:opacity-80",
          variantStyles[variant],
          sizeStyles[size],
          isDisabled && "opacity-50",
          className
        )}
        disabled={isDisabled}
        onPress={handlePress}
        {...props}
      >
        {loading ? (
          <ActivityIndicator
            size="small"
            color={variant === "secondary" || variant === "outline" || variant === "ghost" ? "#171717" : "#ffffff"}
          />
        ) : typeof children === "string" ? (
          <Text
            className={cn(
              "font-semibold",
              variantTextStyles[variant],
              sizeTextStyles[size]
            )}
          >
            {children}
          </Text>
        ) : (
          children
        )}
      </Pressable>
    );
  }
);

Button.displayName = "Button";

