  connectionState: "idle" | "connecting" | "live" | "degraded"
) {
  if (connectionState === "live") {
    return "Live";
  }

  if (connectionState === "connecting") {
    return "Connecting";
  }

  if (connectionState === "degraded") {
    return "Recovering";
  }

  return "Offline";
}

function getConnectionStateVariant(
  connectionState: "idle" | "connecting" | "live" | "degraded"
): "success" | "warning" | "secondary" {
  if (connectionState === "live") {
